param($InputFile, $OutputFile); . "$PSScriptRoot\..\Config\DualLoop.Config.ps1"; if (!(Test-Path $InputFile)) { throw "Missing $InputFile" }; $input = Get-Content $InputFile -Raw; $prompt = "You are Agent 1 (Expand). Given an idea, produce a structured experiment brief with sections: ONE-LINE EXPERIMENT NAME, PROBLEM/OPPORTUNITY, TARGET SILO, HYPOTHESIS, 60-MINUTE STEPS, ASSETS NEEDED, METRIC, SUCCESS CRITERIA, IF IT WORKS, IF IT FLOPS. Input: $input"; $res = Invoke-OllamaCompletion $prompt; Set-Content $OutputFile $res -Encoding UTF8
